  "inlineSchema": "// =============================================================================\n// 🗄️ SCHEMA PRISMA — POSTGRESQL (NEON)\n// =============================================================================\n// Schema do sistema CRAS Agendamentos para PostgreSQL via Prisma\n// Migrado de MongoDB Atlas para PostgreSQL no Neon\n\ngenerator client {\n  provider        = \"prisma-client-js\"\n  // omitApi: necessário no Prisma 5.x para usar `omit: { password: true }` nas queries.\n  // Quando atualizar para Prisma 6+, `omitApi` vira API estável e esta linha pode ser removida.\n  previewFeatures = [\"omitApi\"]\n  binaryTargets   = [\"native\", \"debian-openssl-3.0.x\"]\n}\n\ndatasource db {\n  provider  = \"postgresql\"\n  url       = env(\"DATABASE_URL\")\n  directUrl = env(\"DATABASE_URL_UNPOOLED\")\n}\n\n// ─── Enums ────────────────────────────────────────────────────────────────────\n\nenum Role {\n  admin\n  entrevistador\n  recepcao\n}\n\nenum StatusAgendamento {\n  agendado\n  realizado\n  ausente\n}\n\nenum MotivoAgendamento {\n  atualizacao_cadastral\n  inclusao\n  transferencia_municipio\n  orientacoes_gerais\n}\n\n// ─── Cras ─────────────────────────────────────────────────────────────────────\n\nmodel Cras {\n  id       String  @id @default(cuid())\n  nome     String\n  endereco String\n  telefone String?\n\n  users        User[]\n  appointments Appointment[]\n  blockedSlots BlockedSlot[]\n  logs         Log[]\n\n  @@index([nome])\n  @@map(\"cras\")\n}\n\n// ─── User ─────────────────────────────────────────────────────────────────────\n\nmodel User {\n  id        String   @id @default(cuid())\n  name      String\n  password  String\n  role      Role\n  matricula String   @unique\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  // Soft delete LGPD: em vez de excluir, desativa o usuário.\n  // Preserva referências históricas em logs e agendamentos (FK não fica null).\n  // Auth middleware rejeita tokens de usuários com ativo = false imediatamente\n  // (o cache de autenticação é invalidado em invalidateUser ao desativar).\n  ativo Boolean @default(true)\n\n  // Null para admin, obrigatório para entrevistador/recepcao (validado na app)\n  crasId String? @map(\"cras_id\")\n  cras   Cras?   @relation(fields: [crasId], references: [id])\n\n  // Configurações de agenda (apenas entrevistador usa)\n  horariosDisponiveis String[] @default([\"08:30\", \"09:00\", \"09:30\", \"10:00\", \"10:30\", \"11:00\", \"11:30\", \"13:00\", \"13:30\", \"14:00\", \"14:30\", \"15:00\", \"15:30\", \"16:00\", \"16:30\"])\n  diasAtendimento     Int[]    @default([1, 2, 3, 4, 5])\n  cargaHoraria        Int      @default(8) @map(\"carga_horaria\")\n  horaEntrada         String?  @map(\"hora_entrada\")\n\n  // Relações\n  appointments        Appointment[] @relation(\"EntrevistadorAppointments\")\n  appointmentsCreated Appointment[] @relation(\"CreatedByAppointments\")\n  appointmentsUpdated Appointment[] @relation(\"UpdatedByAppointments\")\n  blockedSlots        BlockedSlot[]\n  logs                Log[]\n\n  @@index([role])\n  @@index([crasId])\n  @@index([crasId, role])\n  @@map(\"users\")\n}\n\n// ─── Appointment ──────────────────────────────────────────────────────────────\n\nmodel Appointment {\n  id String @id @default(cuid())\n\n  entrevistadorId String @map(\"entrevistador_id\")\n  entrevistador   User   @relation(\"EntrevistadorAppointments\", fields: [entrevistadorId], references: [id])\n\n  crasId String @map(\"cras_id\")\n  cras   Cras   @relation(fields: [crasId], references: [id])\n\n  // Dados LGPD — armazenados criptografados (igual ao MongoDB)\n  pessoa    String\n  cpf       String\n  cpfHash   String  @map(\"cpf_hash\")\n  telefone1 String\n  telefone2 String?\n\n  motivo      MotivoAgendamento\n  data        DateTime\n  status      StatusAgendamento @default(agendado)\n  observacoes String?\n\n  createdAt DateTime  @default(now()) @map(\"created_at\")\n  updatedAt DateTime? @map(\"updated_at\")\n\n  createdById String? @map(\"created_by_id\")\n  createdBy   User?   @relation(\"CreatedByAppointments\", fields: [createdById], references: [id])\n  updatedById String? @map(\"updated_by_id\")\n  updatedBy   User?   @relation(\"UpdatedByAppointments\", fields: [updatedById], references: [id])\n\n  @@unique([entrevistadorId, data])\n  @@index([entrevistadorId, data, status])\n  @@index([crasId, data])\n  @@index([cpfHash])\n  @@index([status])\n  @@index([data])\n  @@index([motivo])\n  @@map(\"appointments\")\n}\n\n// ─── BlockedSlot ──────────────────────────────────────────────────────────────\n\nmodel BlockedSlot {\n  id String @id @default(cuid())\n\n  entrevistadorId String @map(\"entrevistador_id\")\n  entrevistador   User   @relation(fields: [entrevistadorId], references: [id])\n\n  crasId String @map(\"cras_id\")\n  cras   Cras   @relation(fields: [crasId], references: [id])\n\n  data      DateTime\n  motivo    String?\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@index([data])\n  @@index([entrevistadorId])\n  @@index([crasId])\n  @@index([entrevistadorId, data])\n  @@index([crasId, data])\n  @@map(\"blocked_slots\")\n}\n\n// ─── Log ──────────────────────────────────────────────────────────────────────\n\nmodel Log {\n  id String @id @default(cuid())\n\n  userId String @map(\"user_id\")\n  user   User   @relation(fields: [userId], references: [id])\n\n  crasId String? @map(\"cras_id\")\n  cras   Cras?   @relation(fields: [crasId], references: [id])\n\n  action  String\n  details String\n  date    DateTime @default(now())\n\n  @@index([userId])\n  @@index([crasId])\n  @@index([action])\n  @@index([userId, date(sort: Desc)])\n  @@index([crasId, date(sort: Desc)])\n  @@map(\"logs\")\n}\n",
